# Generated by openai (gpt-5.4)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

pipeline {
    agent any

    options {
        timestamps()
        disableConcurrentBuilds()
        ansiColor('xterm')
        timeout(time: 60, unit: 'MINUTES')
    }

    parameters {
        text(
            name: 'ARTIFACT_URLS',
            defaultValue: '',
            description: 'One artifact URL per line. Supports HTTP/HTTPS/S3-style URLs if curl can access them.'
        )
        string(
            name: 'DEPLOY_PATH',
            defaultValue: '/opt/app/releases',
            description: 'Target directory on production servers'
        )
        text(
            name: 'PROD_SERVERS',
            defaultValue: 'app01.example.com\napp02.example.com',
            description: 'One production server per line'
        )
        string(
            name: 'SSH_CREDENTIALS_ID',
            defaultValue: 'prod-ssh',
            description: 'Jenkins SSH credentials ID for production servers'
        )
        string(
            name: 'SSH_USER',
            defaultValue: 'deploy',
            description: 'SSH user for production servers'
        )
        booleanParam(
            name: 'CLEAN_REMOTE_BEFORE_DEPLOY',
            defaultValue: false,
            description: 'Remove existing files in target release directory before upload'
        )
        booleanParam(
            name: 'UNPACK_ARCHIVES',
            defaultValue: true,
            description: 'Unpack .zip/.tar/.tar.gz/.tgz archives on remote server after upload'
        )
        booleanParam(
            name: 'VERIFY_CHECKSUMS',
            defaultValue: false,
            description: 'Attempt to download and verify .sha256 checksum files for each artifact'
        )
    }

    environment {
        DOWNLOAD_DIR = "${WORKSPACE}/downloads"
        RELEASE_ID = "${env.BUILD_TAG}"
    }

    stages {
        stage('Validate Parameters') {
            steps {
                script {
                    def urls = params.ARTIFACT_URLS
                        .split(/\r?\n/)
                        .collect { it.trim() }
                        .findAll { it }

                    def servers = params.PROD_SERVERS
                        .split(/\r?\n/)
                        .collect { it.trim() }
                        .findAll { it }

                    if (urls.isEmpty()) {
                        error('ARTIFACT_URLS must contain at least one URL')
                    }

                    if (servers.isEmpty()) {
                        error('PROD_SERVERS must contain at least one server')
                    }

                    urls.each { u ->
                        if (!(u ==~ /^(https?|s3):\/\/.+/)) {
                            error("Unsupported URL format: ${u}")
                        }
                    }

                    env.URL_LIST = urls.join('\n')
                    env.SERVER_LIST = servers.join('\n')
                }
            }
        }

        stage('Prepare Workspace') {
            steps {
                sh '''
                    set -euo pipefail
                    rm -rf "$DOWNLOAD_DIR"
                    mkdir -p "$DOWNLOAD_DIR"
                '''
            }
        }

        stage('Download Artifacts') {
            steps {
                script {
                    def urls = env.URL_LIST.split('\n').findAll { it?.trim() }
                    urls.eachWithIndex { url, idx ->
                        def fileName = url.tokenize('/').last()
                        if (!fileName || fileName.trim().isEmpty()) {
                            fileName = "artifact_${idx + 1}"
                        }

                        sh """
                            set -euo pipefail
                            echo "Downloading: ${url}"
                            curl -fL --retry 3 --retry-delay 2 --connect-timeout 20 -o "${env.DOWNLOAD_DIR}/${fileName}" "${url}"
                            test -s "${env.DOWNLOAD_DIR}/${fileName}"
                        """

                        if (params.VERIFY_CHECKSUMS) {
                            sh """
                                set +e
                                checksum_url="${url}.sha256"
                                checksum_file="${env.DOWNLOAD_DIR}/${fileName}.sha256"
                                echo "Attempting checksum download: \$checksum_url"
                                curl -fsSL --retry 2 --retry-delay 1 -o "\$checksum_file" "\$checksum_url"
                                rc=\$?
                                if [ \$rc -eq 0 ] && [ -s "\$checksum_file" ]; then
                                  cd "${env.DOWNLOAD_DIR}"
                                  if grep -q "${fileName}" "\$checksum_file"; then
                                    sha256sum -c "\$checksum_file"
                                  else
                                    expected=\$(awk '{print \$1}' "\$checksum_file" | head -n1)
                                    actual=\$(sha256sum "${fileName}" | awk '{print \$1}')
                                    [ "\$expected" = "\$actual" ]
                                  fi
                                else
                                  echo "No checksum found for ${url}, failing because VERIFY_CHECKSUMS=true"
                                  exit 1
                                fi
                            """
                        }
                    }
                }
            }
        }

        stage('Deploy to Production') {
            steps {
                script {
                    def servers = env.SERVER_LIST.split('\n').findAll { it?.trim() }
                    sshagent(credentials: [params.SSH_CREDENTIALS_ID]) {
                        servers.each { server ->
                            sh """
                                set -euo pipefail
                                echo "Deploying to ${server}"
                                ssh -o StrictHostKeyChecking=no ${params.SSH_USER}@${server} '
                                    set -euo pipefail
                                    mkdir -p "${params.DEPLOY_PATH}/${env.RELEASE_ID}"
                                    ${params.CLEAN_REMOTE_BEFORE_DEPLOY ? "rm -rf \\"${params.DEPLOY_PATH}/${env.RELEASE_ID}\\"/*" : "true"}
                                '
                                scp -o StrictHostKeyChecking=no "${env.DOWNLOAD_DIR}"/* ${params.SSH_USER}@${server}:"${params.DEPLOY_PATH}/${env.RELEASE_ID}/"
                            """

                            if (params.UNPACK_ARCHIVES) {
                                sh """
                                    set -euo pipefail
                                    ssh -o StrictHostKeyChecking=no ${params.SSH_USER}@${server} '
                                        set -euo pipefail
                                        cd "${params.DEPLOY_PATH}/${env.RELEASE_ID}"
                                        for f in *; do
                                          [ -e "\$f" ] || continue
                                          case "\$f" in
                                            *.tar.gz|*.tgz) tar -xzf "\$f" ;;
                                            *.tar) tar -xf "\$f" ;;
                                            *.zip) unzip -o "\$f" ;;
                                            *) ;;
                                          esac
                                        done
                                        ln -sfn "${params.DEPLOY_PATH}/${env.RELEASE_ID}" "${params.DEPLOY_PATH}/current"
                                    '
                                """
                            } else {
                                sh """
                                    set -euo pipefail
                                    ssh -o StrictHostKeyChecking=no ${params.SSH_USER}@${server} '
                                        set -euo pipefail
                                        ln -sfn "${params.DEPLOY_PATH}/${env.RELEASE_ID}" "${params.DEPLOY_PATH}/current"
                                    '
                                """
                            }
                        }
                    }
                }
            }
        }
    }

    post {
        success {
            echo "Deployment completed successfully for release ${env.RELEASE_ID}"
        }
        failure {
            echo "Deployment failed"
        }
        always {
            sh '''
                set +e
                rm -rf "$DOWNLOAD_DIR"
            '''
        }
    }
}